SIGNALS_RAW_DIR = PROJECT_ROOT / "signals" / "raw"
SIGNALS_MERGED_DIR = PROJECT_ROOT / "signals" / "merged"
SIGNALS_APPROVED_DIR = PROJECT_ROOT / "signals" / "approved"
