    "guard_target_weight": 0.08,
}
DEFAULT_HEADER = [
    "ticket_time",
    "ts_code",
    "side",
    "source_time",
    "source_qty",
    "source_price",
    "source_amount",
    "reason",
    "confirm_status",
    "execute_status",
    "notes",
]


def validate_materialize_ops(ops: list[dict[str, Any]], *, date_tag: str) -> None:
    failed = [op for op in ops if int(op.get("returncode", 0)) != 0]
    if failed:
        details = [
            {
                "step": op.get("step", ""),
                "returncode": op.get("returncode", ""),
                "stderr": op.get("stderr", ""),
                "stdout": op.get("stdout", ""),
            }
            for op in failed
        ]
        raise RuntimeError(
            json.dumps(
                {
                    "date_tag": date_tag,
                    "reason": "materialize_signal_chain_failed",
                    "failed_ops": details,
                },
                ensure_ascii=False,
            )
        )


def parse_float(value: Any, default: float = 0.0) -> float:
    try:
        parsed = float(str(value).replace(",", "").strip())
        return parsed if math.isfinite(parsed) else default
    except Exception:
        return default


def parse_int(value: Any, default: int = 0) -> int:
    try:
        return int(float(str(value).replace(",", "").strip()))
    except Exception:
        return default


def parse_bool(value: Any, default: bool = False) -> bool:
    if value is None:
        return default
    text = str(value).strip().lower()
    if text in {"1", "true", "yes", "y", "ok"}:
        return True
    if text in {"0", "false", "no", "n"}:
        return False
    return default


def normalize_side(value: Any) -> str:
    text = str(value or "").strip().upper()
    if text in {"BUY", "SELL"}:
        return text
    if any(k in text for k in ["买", "BUY", "B", "LONG"]):
        return "BUY"
    if any(k in text for k in ["卖", "SELL", "S", "SHORT"]):
        return "SELL"
    return ""


def normalize_joinquant_code(value: Any) -> str:
    raw = str(value or "").strip().upper()
    if not raw or raw == "NAN":
        return ""
    if raw.endswith(".XSHG") or raw.endswith(".XSHE"):
        return raw
    if raw.endswith(".SH"):
        return raw[:-3] + ".XSHG"
    if raw.endswith(".SZ"):
        return raw[:-3] + ".XSHE"
    if raw.startswith("SH") and len(raw) >= 8:
        return f"{raw[2:8]}.XSHG"
    if raw.startswith("SZ") and len(raw) >= 8:
        return f"{raw[2:8]}.XSHE"
    if raw.isdigit() and len(raw) == 6:
        market = "XSHG" if raw.startswith(("5", "6", "9")) else "XSHE"
        return f"{raw}.{market}"
    return raw


def to_tushare_code(joinquant_code: str) -> str:
    code = normalize_joinquant_code(joinquant_code)
    if "." not in code:
        return ""
    symbol, market = code.split(".", 1)
    if market == "XSHG":
        return f"{symbol}.SH"
    if market == "XSHE":
        return f"{symbol}.SZ"
    return ""


def count_csv_rows(path: Path) -> int:
    if not path.exists():
        return 0
    try:
        with path.open("r", encoding="utf-8", newline="") as handle:
            return max(0, sum(1 for _ in handle) - 1)
    except Exception:
        return 0


def latest_file_by_pattern(pattern: str) -> Path | None:
    files = sorted(REPORT_DIR.glob(pattern), key=*** p: p.stat().st_mtime, reverse=True)
    return files[0] if files else None


def ensure_parent(path: Path) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)


def live_ticket_path(date_tag: str) -> Path:
    return REPORT_DIR / f"stock_signal_tickets_live_{date_tag}.csv"


def legacy_ticket_path(date_tag: str) -> Path:
    return REPORT_DIR / f"stock_signal_tickets_{date_tag}.csv"


def ticket_path(date_tag: str) -> Path:
    return live_ticket_path(date_tag)


def summary_path(date_tag: str) -> Path:
    return REPORT_DIR / f"signal_ticket_bridge_summary_{date_tag}.json"


def resolve_holdings_path(date_tag: str) -> Path | None:
    normalized = str(date_tag or "").strip()
    exact_candidates = [
        REPORT_DIR / f"ths_selected_holdings_{normalized}.csv",
        REPORT_DIR / f"account_holdings_selected_{normalized}.csv",
        REPORT_DIR / "ths_selected_holdings_latest.csv",
        REPORT_DIR / "account_holdings_selected_latest.csv",
    ]
    for path in exact_candidates:
        if path.exists():
            return path

    fallback_patterns = [
        "ths_selected_holdings_*.csv",
        "account_holdings_selected_*.csv",
    ]
    for pattern in fallback_patterns:
        match = latest_file_by_pattern(pattern)
        if match is not None:
            return match
    return None


def summarize_signal_chain_truth(date_tag: str) -> dict[str, Any]:
    merged_path = SIGNALS_MERGED_DIR / f"merged_signals_{date_tag}.csv"
    approved_path = SIGNALS_APPROVED_DIR / f"merged_approved_signals_{date_tag}.csv"
    proposed_path = ORDERS_DIR / f"merged_proposed_orders_{date_tag}.csv"

    def count_by_side(path: Path, column: str, values: set[str], *, require_approved: bool = False) -> int:
        if not path.exists():
            return 0
        try:
            frame = pd.read_csv(path)
        except Exception:
            return 0
        if frame.empty or column not in frame.columns:
            return 0
        if require_approved and "approved" in frame.columns:
            approved_series = frame["approved"].map(lambda x: parse_bool(x, False))
            frame = frame.loc[approved_series].copy()
            if frame.empty:
                return 0
        side_series = frame[column].fillna("").astype(str).str.upper().str.strip()
        return int(side_series.isin(values).sum())

    merged_buy_rows = count_by_side(merged_path, "signal_type", {"BUY", "ADD", "OPEN"})
    merged_sell_rows = count_by_side(merged_path, "signal_type", {"SELL", "REDUCE", "EXIT", "CLOSE"})
    approved_buy_rows = count_by_side(approved_path, "signal_type", {"BUY", "ADD", "OPEN"}, require_approved=True)
    approved_sell_rows = count_by_side(approved_path, "signal_type", {"SELL", "REDUCE", "EXIT", "CLOSE"}, require_approved=True)
    proposed_buy_rows = count_by_side(proposed_path, "action", {"BUY", "ADD", "OPEN"})
    proposed_sell_rows = count_by_side(proposed_path, "action", {"SELL", "REDUCE", "EXIT", "CLOSE"})

    return {
        "merged_signals_file": str(merged_path) if merged_path.exists() else "",
        "approved_signals_file": str(approved_path) if approved_path.exists() else "",
        "proposed_orders_file": str(proposed_path) if proposed_path.exists() else "",
        "merged_buy_rows": merged_buy_rows,
        "merged_sell_rows": merged_sell_rows,
        "approved_buy_rows": approved_buy_rows,
        "approved_sell_rows": approved_sell_rows,
        "blocked_buy_rows": max(0, merged_buy_rows - approved_buy_rows),
        "proposed_buy_rows": proposed_buy_rows,
        "proposed_sell_rows": proposed_sell_rows,
        "buy_signal_visible": merged_buy_rows > 0,
        "buy_signal_ticketed": proposed_buy_rows > 0,
    }


def write_ticket_rows(path: Path, rows: list[dict[str, Any]]) -> None:
    ensure_parent(path)
    frame = pd.DataFrame(rows, columns=DEFAULT_HEADER) if rows else pd.DataFrame(columns=DEFAULT_HEADER)
    frame.to_csv(path, index=False, encoding="utf-8")


def write_summary(path: Path, payload: dict[str, Any]) -> None:
    ensure_parent(path)

